window.exeSearchData = {"page-mp1g9umk-ek3nuokrx":{"name":"Portada","isIndex":true,"fileName":"index.html","fileUrl":"index.html","prePageId":null,"nextPageId":"page-mp1g9umm-zcty6o7gj","blocks":{"20260511120813VRNEWI":{"name":"Text","order":1,"idevices":{"20260511120813NQB88U":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n<div class=\"card success\">\n  <h2>Diseño y desarrollo de un proyecto personal con Arduino</h2>\n  <p><span class=\"badge\">3.º ESO</span><span class=\"badge\">Computación y Robótica</span><span class=\"badge\">8-10 sesiones</span><span class=\"badge\">Castellano</span></p>\n  <p>Este recurso guía al alumnado en el diseño, montaje, programación, documentación y presentación de un proyecto personal con Arduino.</p>\n</div>\n<div class=\"grid\">\n  <div class=\"card\"><h3>Reto</h3><p>Crear un prototipo funcional que responda a una idea o problema sencillo del entorno.</p></div>\n  <div class=\"card\"><h3>Metodología</h3><p>Aprendizaje activo basado en experimentar, probar, depurar, mejorar y comunicar el proceso.</p></div>\n  <div class=\"card\"><h3>Producto final</h3><p>Prototipo Arduino y vídeo explicativo editado con Clipchamp.</p></div>\n</div>\n</div>","jsonProperties":"{\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card success\\\">\\n  <h2>Diseño y desarrollo de un proyecto personal con Arduino</h2>\\n  <p><span class=\\\"badge\\\">3.º ESO</span><span class=\\\"badge\\\">Computación y Robótica</span><span class=\\\"badge\\\">8-10 sesiones</span><span class=\\\"badge\\\">Castellano</span></p>\\n  <p>Este recurso guía al alumnado en el diseño, montaje, programación, documentación y presentación de un proyecto personal con Arduino.</p>\\n</div>\\n<div class=\\\"grid\\\">\\n  <div class=\\\"card\\\"><h3>Reto</h3><p>Crear un prototipo funcional que responda a una idea o problema sencillo del entorno.</p></div>\\n  <div class=\\\"card\\\"><h3>Metodología</h3><p>Aprendizaje activo basado en experimentar, probar, depurar, mejorar y comunicar el proceso.</p></div>\\n  <div class=\\\"card\\\"><h3>Producto final</h3><p>Prototipo Arduino y vídeo explicativo editado con Clipchamp.</p></div>\\n</div>\\n</div>\"}"}}}}},"page-mp1g9umm-zcty6o7gj":{"name":"1. Presentación del proyecto","isIndex":false,"fileName":"1-presentacion-del-proyecto.html","fileUrl":"html/1-presentacion-del-proyecto.html","prePageId":"page-mp1g9umk-ek3nuokrx","nextPageId":"page-mp1g9umo-kq58gu982","blocks":{"20260511120813H24EES":{"name":"Text","order":1,"idevices":{"20260511120813NVBNK3":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n<div class=\"card\">\n  <h2>Presentación y descripción</h2>\n  <p><strong>Título:</strong> Diseño y desarrollo de un proyecto personal con Arduino.</p>\n  <p><strong>Centro de interés:</strong> Robótica educativa, programación y creación de un proyecto tecnológico propio.</p>\n  <p><strong>Nivel:</strong> 3.º de ESO.</p>\n  <p><strong>Temporalización:</strong> 8-10 sesiones.</p>\n  <p><strong>Materia:</strong> Computación y Robótica, con relación a Tecnología y Digitalización, Matemáticas y competencia digital.</p>\n  <p><strong>Descripción general:</strong> el alumnado diseña, monta y programa un proyecto propio con Arduino, aplicando contenidos de electrónica básica, programación y resolución de problemas desde una metodología activa basada en la experimentación y la mejora progresiva.</p>\n  <p><strong>Justificación:</strong> la propuesta parte de una práctica real de aula en la que se observó que el alumnado aprendía de forma más activa cuando manipulaba, probaba, corregía errores y desarrollaba un proyecto personal.</p>\n  <p><a class=\"btn secondary\" href=\"{{context_path}}/content/resources/tarea_2_1_comenzamos_proyecto.pdf\" target=\"_blank\">Abrir Tarea 2.1 original</a></p>\n</div>\n</div>","jsonProperties":"{\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n  <h2>Presentación y descripción</h2>\\n  <p><strong>Título:</strong> Diseño y desarrollo de un proyecto personal con Arduino.</p>\\n  <p><strong>Centro de interés:</strong> Robótica educativa, programación y creación de un proyecto tecnológico propio.</p>\\n  <p><strong>Nivel:</strong> 3.º de ESO.</p>\\n  <p><strong>Temporalización:</strong> 8-10 sesiones.</p>\\n  <p><strong>Materia:</strong> Computación y Robótica, con relación a Tecnología y Digitalización, Matemáticas y competencia digital.</p>\\n  <p><strong>Descripción general:</strong> el alumnado diseña, monta y programa un proyecto propio con Arduino, aplicando contenidos de electrónica básica, programación y resolución de problemas desde una metodología activa basada en la experimentación y la mejora progresiva.</p>\\n  <p><strong>Justificación:</strong> la propuesta parte de una práctica real de aula en la que se observó que el alumnado aprendía de forma más activa cuando manipulaba, probaba, corregía errores y desarrollaba un proyecto personal.</p>\\n  <p><a class=\\\"btn secondary\\\" href=\\\"{{context_path}}/content/resources/tarea_2_1_comenzamos_proyecto.pdf\\\" target=\\\"_blank\\\">Abrir Tarea 2.1 original</a></p>\\n</div>\\n</div>\"}"}}}}},"page-mp1g9umo-kq58gu982":{"name":"2. Protección de datos y derechos digitales","isIndex":false,"fileName":"2-proteccion-de-datos-y-derechos-digitales.html","fileUrl":"html/2-proteccion-de-datos-y-derechos-digitales.html","prePageId":"page-mp1g9umm-zcty6o7gj","nextPageId":"page-mp1g9umo-pgec1y640","blocks":{"20260511120813RGNDGC":{"name":"Text","order":1,"idevices":{"20260511120813AJR9TT":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Cuida tus datos</h2>\n<p>Durante el proyecto se utilizarán herramientas digitales, imágenes, vídeos y posibles publicaciones. Por ello, el alumnado deberá aplicar normas básicas de privacidad, respeto y seguridad.</p>\n<br /><img class=\"responsive\" src=\"{{context_path}}/content/resources/infografia_proteccion_datos.png\" alt=\"Infografía sobre protección de datos y uso seguro de la red\" /></div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"20260511120813AJR9TT\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Cuida tus datos</h2>\\n<p>Durante el proyecto se utilizarán herramientas digitales, imágenes, vídeos y posibles publicaciones. Por ello, el alumnado deberá aplicar normas básicas de privacidad, respeto y seguridad.</p>\\n<br /><img class=\\\"responsive\\\" src=\\\"{{context_path}}/content/resources/infografia_proteccion_datos.png\\\" alt=\\\"Infografía sobre protección de datos y uso seguro de la red\\\" /></div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mp1g9umo-pgec1y640":{"name":"3. Producto final del alumnado","isIndex":false,"fileName":"3-producto-final-del-alumnado.html","fileUrl":"html/3-producto-final-del-alumnado.html","prePageId":"page-mp1g9umo-kq58gu982","nextPageId":"page-mp1g9umq-kn3oauuaq","blocks":{"202605111208138C8D95":{"name":"Text","order":1,"idevices":{"20260511120813QQE2DI":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Producto final</h2>\n<p>El alumnado deberá desarrollar un pequeño vídeo en el que muestre su proyecto de Arduino desarrollado en la asignatura de Robótica en funcionamiento, explicando de forma sencilla qué problema pretende resolver, qué componentes ha utilizado, cómo funciona el montaje y qué resultado obtiene al ponerlo en marcha. Además, deberá incluir una breve explicación del programa o código empleado y, si es posible, comentar las principales dificultades encontradas durante el proceso.<br /><br />La herramienta escogida es <strong>Clipchamp </strong>porque resulta sencilla para el alumnado, permite grabar imagen, pantalla y voz desde un mismo entorno, y además facilita una edición básica sin necesidad de conocimientos avanzados. Por ello, es una opción adecuada para que los alumnos puedan centrarse en explicar su proyecto con claridad sin que la parte técnica de la grabación complique excesivamente la tarea.</p>\n<h3>Requisitos mínimos del vídeo</h3>\n<ul class=\"checklist\">\n<li>Mostrar el prototipo funcionando.</li>\n<li>Explicar qué problema o necesidad pretende resolver.</li>\n<li>Identificar los componentes utilizados.</li>\n<li>Explicar de forma sencilla el montaje y el código.</li>\n<li>Comentar dificultades encontradas y mejoras posibles.</li>\n</ul>\n<br /></div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"20260511120813QQE2DI\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Producto final</h2>\\n<p>El alumnado deberá desarrollar un pequeño vídeo en el que muestre su proyecto de Arduino desarrollado en la asignatura de Robótica en funcionamiento, explicando de forma sencilla qué problema pretende resolver, qué componentes ha utilizado, cómo funciona el montaje y qué resultado obtiene al ponerlo en marcha. Además, deberá incluir una breve explicación del programa o código empleado y, si es posible, comentar las principales dificultades encontradas durante el proceso.<br /><br />La herramienta escogida es <strong>Clipchamp </strong>porque resulta sencilla para el alumnado, permite grabar imagen, pantalla y voz desde un mismo entorno, y además facilita una edición básica sin necesidad de conocimientos avanzados. Por ello, es una opción adecuada para que los alumnos puedan centrarse en explicar su proyecto con claridad sin que la parte técnica de la grabación complique excesivamente la tarea.</p>\\n<h3>Requisitos mínimos del vídeo</h3>\\n<ul class=\\\"checklist\\\">\\n<li>Mostrar el prototipo funcionando.</li>\\n<li>Explicar qué problema o necesidad pretende resolver.</li>\\n<li>Identificar los componentes utilizados.</li>\\n<li>Explicar de forma sencilla el montaje y el código.</li>\\n<li>Comentar dificultades encontradas y mejoras posibles.</li>\\n</ul>\\n<br /></div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mp1g9umq-kn3oauuaq":{"name":"4. Curación de contenidos","isIndex":false,"fileName":"4-curacion-de-contenidos.html","fileUrl":"html/4-curacion-de-contenidos.html","prePageId":"page-mp1g9umo-pgec1y640","nextPageId":"page-mp1g9umq-bgoaiah90","blocks":{"20260511120813P11ZDZ":{"name":"Text","order":1,"idevices":{"20260511120813DQI86X":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Herramientas de curación de contenidos</h2>\n<p>En este apartado se incorporan los recursos seleccionados para orientar el trabajo del docente y del alumnado.</p>\n<div class=\"grid\">\n<div class=\"card\">\n<h3>Curación para el docente</h3>\n<p>Banco de recursos de apoyo para planificar, ejemplificar y resolver dudas durante la situación de aprendizaje.</p>\n<p><a class=\"btn\" href=\"https://www.symbaloo.com/shared/AAAAAZHl8PUAA41-4ql-Uw==\" target=\"_blank\" rel=\"noopener\">Abrir Symbaloo</a></p>\n</div>\n</div>\n</div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"20260511120813DQI86X\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Herramientas de curación de contenidos</h2>\\n<p>En este apartado se incorporan los recursos seleccionados para orientar el trabajo del docente y del alumnado.</p>\\n<div class=\\\"grid\\\">\\n<div class=\\\"card\\\">\\n<h3>Curación para el docente</h3>\\n<p>Banco de recursos de apoyo para planificar, ejemplificar y resolver dudas durante la situación de aprendizaje.</p>\\n<p><a class=\\\"btn\\\" href=\\\"https://www.symbaloo.com/shared/AAAAAZHl8PUAA41-4ql-Uw==\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">Abrir Symbaloo</a></p>\\n</div>\\n</div>\\n</div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mp1g9umq-bgoaiah90":{"name":"5. Línea temporal del proyecto","isIndex":false,"fileName":"5-linea-temporal-del-proyecto.html","fileUrl":"html/5-linea-temporal-del-proyecto.html","prePageId":"page-mp1g9umq-kn3oauuaq","nextPageId":"page-mp1g9umr-mz5b8jhwj","blocks":{"20260511120813U382B6":{"name":"Text","order":1,"idevices":{"20260511120813H0HXI0":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n<div class=\"card\">\n  <h2>Plan de trabajo y línea temporal</h2>\n  <p>La secuencia de actividades se presenta en una línea temporal para que el alumnado pueda anticipar qué debe hacer en cada momento.</p>\n  <p><a class=\"btn\" href=\"https://bubbl.us/ODkwNjU3OS82NTI1NTk4L2U1ODZkMzU3MjcyYTFlYTI2MmJhNGExZTMwZGI4MDA20\" target=\"_blank\">Abrir línea temporal en Bubbl.us</a></p>\n  <iframe src=\"https://bubbl.us/ODkwNjU3OS82NTI1NTk4L2U1ODZkMzU3MjcyYTFlYTI2MmJhNGExZTMwZGI4MDA20\" title=\"Línea temporal del proyecto en Bubbl.us\"></iframe>\n</div>\n</div>","jsonProperties":"{\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n  <h2>Plan de trabajo y línea temporal</h2>\\n  <p>La secuencia de actividades se presenta en una línea temporal para que el alumnado pueda anticipar qué debe hacer en cada momento.</p>\\n  <p><a class=\\\"btn\\\" href=\\\"https://bubbl.us/ODkwNjU3OS82NTI1NTk4L2U1ODZkMzU3MjcyYTFlYTI2MmJhNGExZTMwZGI4MDA20\\\" target=\\\"_blank\\\">Abrir línea temporal en Bubbl.us</a></p>\\n  <iframe src=\\\"https://bubbl.us/ODkwNjU3OS82NTI1NTk4L2U1ODZkMzU3MjcyYTFlYTI2MmJhNGExZTMwZGI4MDA20\\\" title=\\\"Línea temporal del proyecto en Bubbl.us\\\"></iframe>\\n</div>\\n</div>\"}"}}}}},"page-mp1g9umr-mz5b8jhwj":{"name":"6. Actividades y criterios de evaluación","isIndex":false,"fileName":"6-actividades-y-criterios-de-evaluacion.html","fileUrl":"html/6-actividades-y-criterios-de-evaluacion.html","prePageId":"page-mp1g9umq-bgoaiah90","nextPageId":"page-mp1g9umr-0mithaq0a","blocks":{"20260511120813M6U9LC":{"name":"Text","order":1,"idevices":{"20260511120813JN5KLL":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Relación entre tareas y criterios de evaluación</h2>\n<p>La evaluación se plantea de forma criterial, continua y formativa. La siguiente tabla resume la relación entre tareas, criterios, agrupamiento, tiempo y herramientas.</p>\n<div class=\"table-wrap\">\n<table>\n<thead>\n<tr>\n<th>Tarea</th>\n<th>Criterios</th>\n<th>Agrupamiento</th>\n<th>Tiempo</th>\n<th>Herramienta</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Recordatorio inicial sobre Arduino, placa, entradas/salidas y componentes</td>\n<td>1.1 / 1.3 / 1.4</td>\n<td>Grupo clase</td>\n<td>1 sesión</td>\n<td>Presentación del profesor; Arduino IDE</td>\n</tr>\n<tr>\n<td>Elección de la idea del proyecto y explicación de qué quiere resolver</td>\n<td>2.1</td>\n<td>Individual</td>\n<td>1 sesión</td>\n<td>Navegador de internet</td>\n</tr>\n<tr>\n<td>Diseño del circuito y del algoritmo</td>\n<td>1.1 / 1.3 / 2.1</td>\n<td>Individual</td>\n<td>2 sesiones</td>\n<td>Tinkercad Circuits</td>\n</tr>\n<tr>\n<td>Simulación previa del montaje</td>\n<td>2.1 / 3.1</td>\n<td>Individual</td>\n<td>2 sesiones</td>\n<td>Tinkercad Circuits</td>\n</tr>\n<tr>\n<td>Montaje físico del prototipo con Arduino</td>\n<td>1.1 / 1.4 / 3.1</td>\n<td>Individual</td>\n<td>2 sesiones</td>\n<td>Kit Arduino; protoboard; componentes</td>\n</tr>\n<tr>\n<td>Programación del proyecto y primeras pruebas</td>\n<td>1.3 / 2.1 / 3.1</td>\n<td>Individual</td>\n<td>2 sesiones</td>\n<td>Arduino IDE</td>\n</tr>\n<tr>\n<td>Corrección de errores y mejora del funcionamiento</td>\n<td>2.1 / 3.1</td>\n<td>Individual</td>\n<td>2 sesiones</td>\n<td>Arduino IDE; Tinkercad</td>\n</tr>\n<tr>\n<td>Grabación o presentación del proyecto funcionando</td>\n<td>2.1 / 3.1</td>\n<td>Individual</td>\n<td>1 sesión</td>\n<td>Clipchamp</td>\n</tr>\n<tr>\n<td>Exposición final explicando componentes, código y resultado</td>\n<td>2.1</td>\n<td>Grupo clase</td>\n<td>1 sesión</td>\n<td>Clipchamp</td>\n</tr>\n</tbody>\n</table>\n</div>\n<br /></div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"20260511120813JN5KLL\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Relación entre tareas y criterios de evaluación</h2>\\n<p>La evaluación se plantea de forma criterial, continua y formativa. La siguiente tabla resume la relación entre tareas, criterios, agrupamiento, tiempo y herramientas.</p>\\n<div class=\\\"table-wrap\\\">\\n<table>\\n<thead>\\n<tr>\\n<th>Tarea</th>\\n<th>Criterios</th>\\n<th>Agrupamiento</th>\\n<th>Tiempo</th>\\n<th>Herramienta</th>\\n</tr>\\n</thead>\\n<tbody>\\n<tr>\\n<td>Recordatorio inicial sobre Arduino, placa, entradas/salidas y componentes</td>\\n<td>1.1 / 1.3 / 1.4</td>\\n<td>Grupo clase</td>\\n<td>1 sesión</td>\\n<td>Presentación del profesor; Arduino IDE</td>\\n</tr>\\n<tr>\\n<td>Elección de la idea del proyecto y explicación de qué quiere resolver</td>\\n<td>2.1</td>\\n<td>Individual</td>\\n<td>1 sesión</td>\\n<td>Navegador de internet</td>\\n</tr>\\n<tr>\\n<td>Diseño del circuito y del algoritmo</td>\\n<td>1.1 / 1.3 / 2.1</td>\\n<td>Individual</td>\\n<td>2 sesiones</td>\\n<td>Tinkercad Circuits</td>\\n</tr>\\n<tr>\\n<td>Simulación previa del montaje</td>\\n<td>2.1 / 3.1</td>\\n<td>Individual</td>\\n<td>2 sesiones</td>\\n<td>Tinkercad Circuits</td>\\n</tr>\\n<tr>\\n<td>Montaje físico del prototipo con Arduino</td>\\n<td>1.1 / 1.4 / 3.1</td>\\n<td>Individual</td>\\n<td>2 sesiones</td>\\n<td>Kit Arduino; protoboard; componentes</td>\\n</tr>\\n<tr>\\n<td>Programación del proyecto y primeras pruebas</td>\\n<td>1.3 / 2.1 / 3.1</td>\\n<td>Individual</td>\\n<td>2 sesiones</td>\\n<td>Arduino IDE</td>\\n</tr>\\n<tr>\\n<td>Corrección de errores y mejora del funcionamiento</td>\\n<td>2.1 / 3.1</td>\\n<td>Individual</td>\\n<td>2 sesiones</td>\\n<td>Arduino IDE; Tinkercad</td>\\n</tr>\\n<tr>\\n<td>Grabación o presentación del proyecto funcionando</td>\\n<td>2.1 / 3.1</td>\\n<td>Individual</td>\\n<td>1 sesión</td>\\n<td>Clipchamp</td>\\n</tr>\\n<tr>\\n<td>Exposición final explicando componentes, código y resultado</td>\\n<td>2.1</td>\\n<td>Grupo clase</td>\\n<td>1 sesión</td>\\n<td>Clipchamp</td>\\n</tr>\\n</tbody>\\n</table>\\n</div>\\n<br /></div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mp1g9umr-0mithaq0a":{"name":"7. Instrumentos de evaluación","isIndex":false,"fileName":"7-instrumentos-de-evaluacion.html","fileUrl":"html/7-instrumentos-de-evaluacion.html","prePageId":"page-mp1g9umr-mz5b8jhwj","nextPageId":"page-mp1g9ums-3x4sxvs36","blocks":{"20260511120813MMYCP3":{"name":"Text","order":1,"idevices":{"2026051112081388ZO6E":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Instrumentos de evaluación</h2>\n<p>Se emplearán tres instrumentos complementarios para recoger evidencias en distintos momentos del proceso.</p>\n<div class=\"table-wrap\">\n<table>\n<thead>\n<tr>\n<th>Instrumento</th>\n<th>Momento</th>\n<th>Qué evalúa</th>\n<th>Técnica</th>\n<th>Peso orientativo</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Lista de cotejo de seguimiento</td>\n<td>Durante el proceso</td>\n<td>Planificación, autonomía, montaje, depuración y aprovechamiento del tiempo</td>\n<td>Observación sistemática</td>\n<td>20 %</td>\n</tr>\n<tr>\n<td>Escala de valoración del proyecto final</td>\n<td>Al terminar el prototipo</td>\n<td>Calidad técnica y funcional del producto</td>\n<td>Análisis del producto</td>\n<td>50 %</td>\n</tr>\n<tr>\n<td>Rúbrica de presentación del proyecto</td>\n<td>Exposición final</td>\n<td>Comunicación oral, explicación técnica y demostración</td>\n<td>Valoración analítica</td>\n<td>30 %</td>\n</tr>\n</tbody>\n</table>\n</div>\n<p></p>\n</div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"2026051112081388ZO6E\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Instrumentos de evaluación</h2>\\n<p>Se emplearán tres instrumentos complementarios para recoger evidencias en distintos momentos del proceso.</p>\\n<div class=\\\"table-wrap\\\">\\n<table>\\n<thead>\\n<tr>\\n<th>Instrumento</th>\\n<th>Momento</th>\\n<th>Qué evalúa</th>\\n<th>Técnica</th>\\n<th>Peso orientativo</th>\\n</tr>\\n</thead>\\n<tbody>\\n<tr>\\n<td>Lista de cotejo de seguimiento</td>\\n<td>Durante el proceso</td>\\n<td>Planificación, autonomía, montaje, depuración y aprovechamiento del tiempo</td>\\n<td>Observación sistemática</td>\\n<td>20 %</td>\\n</tr>\\n<tr>\\n<td>Escala de valoración del proyecto final</td>\\n<td>Al terminar el prototipo</td>\\n<td>Calidad técnica y funcional del producto</td>\\n<td>Análisis del producto</td>\\n<td>50 %</td>\\n</tr>\\n<tr>\\n<td>Rúbrica de presentación del proyecto</td>\\n<td>Exposición final</td>\\n<td>Comunicación oral, explicación técnica y demostración</td>\\n<td>Valoración analítica</td>\\n<td>30 %</td>\\n</tr>\\n</tbody>\\n</table>\\n</div>\\n<p></p>\\n</div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mp1g9ums-3x4sxvs36":{"name":"8. Atención a la diversidad y DUA","isIndex":false,"fileName":"8-atencion-a-la-diversidad-y-dua.html","fileUrl":"html/8-atencion-a-la-diversidad-y-dua.html","prePageId":"page-mp1g9umr-0mithaq0a","nextPageId":"page-mp1g9ums-hta9nbp00","blocks":{"20260511120813ZSGMXX":{"name":"Text","order":1,"idevices":{"20260511120813BCX1M2":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n<div class=\"card\">\n  <h2>Atención a la diversidad y principios DUA</h2>\n  <p>El diseño del proyecto contempla diferentes formas de acceso, participación y expresión para favorecer que todo el alumnado pueda progresar.</p>\n  <div class=\"grid\">\n    <div class=\"card\"><h3>Representación</h3><ul><li>Explicaciones orales y visuales.</li><li>Esquemas de montaje.</li><li>Ejemplos de código comentado.</li><li>Uso de simuladores antes del montaje físico.</li></ul></div>\n    <div class=\"card\"><h3>Acción y expresión</h3><ul><li>Elección de la idea del proyecto.</li><li>Entrega mediante prototipo, explicación oral y vídeo.</li><li>Posibilidad de adaptar la complejidad técnica.</li></ul></div>\n    <div class=\"card\"><h3>Implicación</h3><ul><li>Reto cercano y manipulativo.</li><li>Feedback durante el proceso.</li><li>Mejora progresiva a partir del error.</li></ul></div>\n  </div>\n</div>\n</div>","jsonProperties":"{\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n  <h2>Atención a la diversidad y principios DUA</h2>\\n  <p>El diseño del proyecto contempla diferentes formas de acceso, participación y expresión para favorecer que todo el alumnado pueda progresar.</p>\\n  <div class=\\\"grid\\\">\\n    <div class=\\\"card\\\"><h3>Representación</h3><ul><li>Explicaciones orales y visuales.</li><li>Esquemas de montaje.</li><li>Ejemplos de código comentado.</li><li>Uso de simuladores antes del montaje físico.</li></ul></div>\\n    <div class=\\\"card\\\"><h3>Acción y expresión</h3><ul><li>Elección de la idea del proyecto.</li><li>Entrega mediante prototipo, explicación oral y vídeo.</li><li>Posibilidad de adaptar la complejidad técnica.</li></ul></div>\\n    <div class=\\\"card\\\"><h3>Implicación</h3><ul><li>Reto cercano y manipulativo.</li><li>Feedback durante el proceso.</li><li>Mejora progresiva a partir del error.</li></ul></div>\\n  </div>\\n</div>\\n</div>\"}"}}}}},"page-mp1g9ums-hta9nbp00":{"name":"9. Guía didáctica","isIndex":false,"fileName":"9-guia-didactica.html","fileUrl":"html/9-guia-didactica.html","prePageId":"page-mp1g9ums-3x4sxvs36","nextPageId":"page-mp1g9umu-xx6k4dcng","blocks":{"202605111208138AU5DA":{"name":"Text","order":1,"idevices":{"20260511120813ZGDEDJ":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n<div class=\"card\">\n  <h2>Guía didáctica para el profesorado</h2>\n  <p>Esta guía resume los elementos necesarios para aplicar la situación de aprendizaje en el aula.</p>\n  <ul class=\"checklist\">\n    <li><strong>Etapa y nivel:</strong> 3.º ESO.</li>\n    <li><strong>Materia:</strong> Computación y Robótica.</li>\n    <li><strong>Duración:</strong> 8-10 sesiones.</li>\n    <li><strong>Metodología:</strong> aprendizaje basado en proyectos, experimentación, simulación, montaje físico y comunicación del producto.</li>\n    <li><strong>Evaluación:</strong> criterial, continua y formativa.</li>\n    <li><strong>Herramientas:</strong> Arduino IDE, Tinkercad Circuits, Clipchamp, Symbaloo y Bubbl.us.</li>\n  </ul>\n  <p>Se recomienda comprobar previamente placas, componentes, cableado, cuentas, conexión a internet y alternativas sin conexión para evitar interrupciones.</p>\n  <p><a class=\"btn secondary\" href=\"{{context_path}}/content/resources/tarea_6_1_criterios_evaluacion.pdf\" target=\"_blank\">Documento tareas-criterios</a></p>\n</div>\n</div>","jsonProperties":"{\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n  <h2>Guía didáctica para el profesorado</h2>\\n  <p>Esta guía resume los elementos necesarios para aplicar la situación de aprendizaje en el aula.</p>\\n  <ul class=\\\"checklist\\\">\\n    <li><strong>Etapa y nivel:</strong> 3.º ESO.</li>\\n    <li><strong>Materia:</strong> Computación y Robótica.</li>\\n    <li><strong>Duración:</strong> 8-10 sesiones.</li>\\n    <li><strong>Metodología:</strong> aprendizaje basado en proyectos, experimentación, simulación, montaje físico y comunicación del producto.</li>\\n    <li><strong>Evaluación:</strong> criterial, continua y formativa.</li>\\n    <li><strong>Herramientas:</strong> Arduino IDE, Tinkercad Circuits, Clipchamp, Symbaloo y Bubbl.us.</li>\\n  </ul>\\n  <p>Se recomienda comprobar previamente placas, componentes, cableado, cuentas, conexión a internet y alternativas sin conexión para evitar interrupciones.</p>\\n  <p><a class=\\\"btn secondary\\\" href=\\\"{{context_path}}/content/resources/tarea_6_1_criterios_evaluacion.pdf\\\" target=\\\"_blank\\\">Documento tareas-criterios</a></p>\\n</div>\\n</div>\"}"}}}}},"page-mp1g9umu-xx6k4dcng":{"name":"10. Créditos","isIndex":false,"fileName":"10-creditos.html","fileUrl":"html/10-creditos.html","prePageId":"page-mp1g9ums-hta9nbp00","nextPageId":null,"blocks":{"20260511120813NON3CK":{"name":"Text","order":1,"idevices":{"20260511120813G8FIY3":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <div class=\"exe-text-template\">\n<div class=\"card\">\n<h2>Créditos</h2>\n<p><strong>Autoría:</strong> José Antonio Díaz Rubio.</p>\n<p><strong>Descripción:</strong> Recurso educativo abierto para guiar al alumnado de 3.º ESO en una Situación de aprendizaje consistente en la realización de un proyecto.</p>\n</div>\n</div>\n</div>","jsonProperties":"{\"ideviceId\":\"20260511120813G8FIY3\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<div class=\\\"exe-text-template\\\">\\n<div class=\\\"card\\\">\\n<h2>Créditos</h2>\\n<p><strong>Autoría:</strong> José Antonio Díaz Rubio.</p>\\n<p><strong>Descripción:</strong> Recurso educativo abierto para guiar al alumnado de 3.º ESO en una Situación de aprendizaje consistente en la realización de un proyecto.</p>\\n</div>\\n</div>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}}};